1367 Value *SCEVExpander::FindValueInExprValueMap(
1368     const SCEV *S, const Instruction *InsertPt,
1369     SmallVectorImpl<Instruction *> &DropPoisonGeneratingInsts) {
1370   // If the expansion is not in CanonicalMode, and the SCEV contains any
1371   // sub scAddRecExpr type SCEV, it is required to expand the SCEV literally.
1372   if (!CanonicalMode && SE.containsAddRecurrence(S))
1373     return nullptr;
1374 
1375   // If S is a constant, it may be worse to reuse an existing Value.
1376   if (isa<SCEVConstant>(S))
1377     return nullptr;
1378 
1379   for (Value *V : SE.getSCEVValues(S)) {
1380     Instruction *EntInst = dyn_cast<Instruction>(V);
1381     if (!EntInst)
1382       continue;
1383 
1384     // Choose a Value from the set which dominates the InsertPt.
1385     // InsertPt should be inside the Value's parent loop so as not to break
1386     // the LCSSA form.
1387     assert(EntInst->getFunction() == InsertPt->getFunction());
1388     if (S->getType() != V->getType() || !SE.DT.dominates(EntInst, InsertPt) ||
1389         !(SE.LI.getLoopFor(EntInst->getParent()) == nullptr ||
1390           SE.LI.getLoopFor(EntInst->getParent())->contains(InsertPt)))
1391       continue;
1392 
1393     // Make sure reusing the instruction is poison-safe.
1394     if (SE.canReuseInstruction(S, EntInst, DropPoisonGeneratingInsts))
1395       return V;
1396     DropPoisonGeneratingInsts.clear();
1397   }
1398   return nullptr;
1399 }
