1401 // The expansion of SCEV will either reuse a previous Value in ExprValueMap,
1402 // or expand the SCEV literally. Specifically, if the expansion is in LSRMode,
1403 // and the SCEV contains any sub scAddRecExpr type SCEV, it will be expanded
1404 // literally, to prevent LSR's transformed SCEV from being reverted. Otherwise,
1405 // the expansion will try to reuse Value from ExprValueMap, and only when it
1406 // fails, expand the SCEV literally.
1407 Value *SCEVExpander::expand(const SCEV *S) {
1408   // Compute an insertion point for this SCEV object. Hoist the instructions
1409   // as far out in the loop nest as possible.
1410   BasicBlock::iterator InsertPt = Builder.GetInsertPoint();
1411 
1412   // We can move insertion point only if there is no div or rem operations
1413   // otherwise we are risky to move it over the check for zero denominator.
1414   auto SafeToHoist = [](const SCEV *S) {
1415     return !SCEVExprContains(S, [](const SCEV *S) {
1416               if (const auto *D = dyn_cast<SCEVUDivExpr>(S)) {
1417                 if (const auto *SC = dyn_cast<SCEVConstant>(D->getRHS()))
1418                   // Division by non-zero constants can be hoisted.
1419                   return SC->getValue()->isZero();
1420                 // All other divisions should not be moved as they may be
1421                 // divisions by zero and should be kept within the
1422                 // conditions of the surrounding loops that guard their
1423                 // execution (see PR35406).
1424                 return true;
1425               }
1426               return false;
1427             });
1428   };
1429   if (SafeToHoist(S)) {
1430     for (Loop *L = SE.LI.getLoopFor(Builder.GetInsertBlock());;
1431          L = L->getParentLoop()) {
1432       if (SE.isLoopInvariant(S, L)) {
1433         if (!L) break;
1434         if (BasicBlock *Preheader = L->getLoopPreheader()) {
1435           InsertPt = Preheader->getTerminator()->getIterator();
1436         } else {
1437           // LSR sets the insertion point for AddRec start/step values to the
1438           // block start to simplify value reuse, even though it's an invalid
1439           // position. SCEVExpander must correct for this in all cases.
1440           InsertPt = L->getHeader()->getFirstInsertionPt();
1441         }
1442       } else {
1443         // If the SCEV is computable at this level, insert it into the header
1444         // after the PHIs (and after any other instructions that we've inserted
1445         // there) so that it is guaranteed to dominate any user inside the loop.
1446         if (L && SE.hasComputableLoopEvolution(S, L) && !PostIncLoops.count(L))
