1491           NNI->setNonNeg(true);
1492       }
1493     }
1494   }
1495   // Remember the expanded value for this SCEV at this location.
1496   //
1497   // This is independent of PostIncLoops. The mapped value simply materializes
1498   // the expression at this insertion point. If the mapped value happened to be
1499   // a postinc expansion, it could be reused by a non-postinc user, but only if
1500   // its insertion point was already at the head of the loop.
1501   InsertedExpressions[std::make_pair(S, &*InsertPt)] = V;
1502   return V;
1503 }
