1505 void SCEVExpander::rememberInstruction(Value *I) {
1506   auto DoInsert = [this](Value *V) {
1507     if (!PostIncLoops.empty())
1508       InsertedPostIncValues.insert(V);
1509     else
1510       InsertedValues.insert(V);
1511   };
1512   DoInsert(I);
1513 }
