1515 void SCEVExpander::replaceCongruentIVInc(
1516     PHINode *&Phi, PHINode *&OrigPhi, Loop *L, const DominatorTree *DT,
1517     SmallVectorImpl<WeakTrackingVH> &DeadInsts) {
1518   BasicBlock *LatchBlock = L->getLoopLatch();
1519   if (!LatchBlock)
