1521 
1522   Instruction *OrigInc =
1523       dyn_cast<Instruction>(OrigPhi->getIncomingValueForBlock(LatchBlock));
1524   Instruction *IsomorphicInc =
1525       dyn_cast<Instruction>(Phi->getIncomingValueForBlock(LatchBlock));
1526   if (!OrigInc || !IsomorphicInc)
1527     return;
1528 
1529   // If this phi has the same width but is more canonical, replace the
1530   // original with it. As part of the "more canonical" determination,
1531   // respect a prior decision to use an IV chain.
1532   if (OrigPhi->getType() == Phi->getType() &&
1533       !(ChainedPhis.count(Phi) ||
1534         isExpandedAddRecExprPHI(OrigPhi, OrigInc, L)) &&
1535       (ChainedPhis.count(Phi) ||
1536        isExpandedAddRecExprPHI(Phi, IsomorphicInc, L))) {
1537     std::swap(OrigPhi, Phi);
1538     std::swap(OrigInc, IsomorphicInc);
1539   }
1540 
1541   // Replacing the congruent phi is sufficient because acyclic
1542   // redundancy elimination, CSE/GVN, should handle the
1543   // rest. However, once SCEV proves that a phi is congruent,
1544   // it's often the head of an IV user cycle that is isomorphic
1545   // with the original phi. It's worth eagerly cleaning up the
1546   // common case of a single IV increment so that DeleteDeadPHIs
1547   // can remove cycles that had postinc uses.
